import { GoogleGenAI, Type } from "@google/genai";
import { ParsedBill, Transaction, BlogPost, OpsHealthSnapshot } from "../types";

const DUKAAN_AI_INSTRUCTION = `You are DukaanMitra AI, a WhatsApp-first accounting assistant for Indian shops. STRICT JSON output only.`;

const RESPONSE_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    action: { type: Type.STRING, enum: ["add_entry", "analyze_data", "get_summary", "add_bulk_entries", "clarification_required"] },
    customer_name: { type: Type.STRING },
    item: { type: Type.STRING },
    items: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          item: { type: Type.STRING },
          amount: { type: Type.NUMBER }
        }
      }
    },
    amount: { type: Type.NUMBER },
    confidence: { type: Type.STRING, enum: ["high", "medium", "low"] },
    user_message: { type: Type.STRING }
  },
  required: ["action", "confidence", "user_message"]
};

export const parseMessage = async (text: string, context?: string): Promise<ParsedBill> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [{ parts: [{ text: `Context: ${context || 'None'}\nUser Message: ${text}` }] }],
      config: {
        systemInstruction: DUKAAN_AI_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) {
    return { action: 'clarification_required', user_message: "Network issue.", confidence: 'low' };
  }
};

