  patch_code: string, 
  impact_analysis: string,
  architect_note: string 
}> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `System State: ${systemState}\nOps Command: ${query}`,
      config: {
        systemInstruction: `You are the Sovereign System Architect for DukaanMitra. 
        Your goal is to optimize the platform infrastructure, fix scaling bottlenecks, and suggest functional code upgrades.
        Return a highly technical diagnosis and a "patch_code" which is a snippet of code or configuration to improve the system.
        Be industrial, precise, and authoritative.`,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            diagnosis: { type: Type.STRING },
            patch_code: { type: Type.STRING, description: "TypeScript/Node.js/YAML code or configuration patch." },
            impact_analysis: { type: Type.STRING },
            architect_note: { type: Type.STRING }
          },
          required: ["diagnosis", "patch_code", "impact_analysis"]
        },
        thinkingConfig: { thinkingBudget: 8000 }
      }
    });
