export const generateAssistantResponse = async (prompt: string, role: 'ops' | 'merchant', history: any[] = []): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const instructions = role === 'ops' 
    ? "You are the DukaanMitra Technical Assistant. Help the Ops team with system architecture, debugging, and infrastructure scaling queries. Be technical and precise."
    : "You are the DukaanMitra Merchant Buddy. Help shop owners with billing, marketing, and using the app. Speak in friendly Hinglish where appropriate.";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [
        ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: instructions,
        thinkingConfig: role === 'ops' ? { thinkingBudget: 4000 } : undefined
      }
    });
    return response.text || "Assistant error";
  } catch {
    return "Offline";
  }
};

