export const getNearbyLogistics = async (lat: number, lng: number): Promise<{ text: string, links: { uri: string, title: string }[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: `Find regional wholesalers and logistics providers near ${lat}, ${lng} for retail.`,
    config: { tools: [{ googleMaps: {} }, { googleSearch: {} }], toolConfig: { retrievalConfig: { latLng: { latitude: lat, longitude: lng } } } }
  });
  const text = response.text || "";
  const links = (response.candidates?.[0]?.groundingMetadata?.groundingChunks || [])
    .map((c: any) => c.web ? { uri: c.web.uri, title: c.web.title } : (c.maps ? { uri: c.maps.uri, title: c.maps.title } : null))
    .filter(Boolean);
  return { text, links };
};

