      </button>

      <div className={`fixed bottom-28 right-8 w-[400px] h-[600px] bg-white rounded-[2.5rem] shadow-[0_20px_60px_-15px_rgba(0,0,0,0.3)] border border-slate-200 flex flex-col overflow-hidden transition-all duration-300 z-50 transform origin-bottom-right ${
        isOpen ? 'scale-100 opacity-100' : 'scale-0 opacity-0 pointer-events-none'
      }`}>
        <div className={`p-6 text-white flex items-center justify-between ${role === 'ops' ? 'bg-slate-900' : 'bg-indigo-600'}`}>
          <div className="flex items-center space-x-3">
            <div className={`w-10 h-10 rounded-2xl flex items-center justify-center text-xl shadow-lg ${role === 'ops' ? 'bg-rose-600' : 'bg-white/20'}`}>
              {role === 'ops' ? '🧠' : '✨'}
            </div>
            <div>
              <h3 className="font-bold text-sm tracking-tight">{role === 'ops' ? 'System Brain' : 'Merchant Buddy'}</h3>
              <div className="flex items-center space-x-1.5 mt-0.5">
                <span className={`w-1.5 h-1.5 rounded-full ${isLiveMode ? 'bg-emerald-500 animate-ping' : 'bg-emerald-500 animate-pulse'}`}></span>
                <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{isLiveMode ? 'Voice Link Active' : 'Gemini 3 Pro'}</span>
              </div>
            </div>
          </div>
          <button 
