import React, { useState, useEffect } from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { Customer, Transaction, View, OpsHealthSnapshot, AppliedPatch, ShardHealth } from '../types';
import { generateOpsDailySummary, getSystemOptimization } from '../services/geminiService';

interface DashboardProps {
  customers: Customer[];
  transactions: Transaction[];
  shards: ShardHealth[];
  setShards: React.Dispatch<React.SetStateAction<ShardHealth[]>>;
  appliedPatches: AppliedPatch[];
  setAppliedPatches: React.Dispatch<React.SetStateAction<AppliedPatch[]>>;
  setView: (view: View) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ customers, transactions, shards, setShards, appliedPatches, setAppliedPatches, setView }) => {
  const [health, setHealth] = useState<OpsHealthSnapshot | null>(null);
  const [resolverInput, setResolverInput] = useState('');
  const [isResolving, setIsResolving] = useState(false);
  const [isDeploying, setIsDeploying] = useState(false);
  const [resolutions, setResolutions] = useState<any[]>([]);

  useEffect(() => {
    const fetchHealth = async () => {
      const avgLatency = shards.reduce((acc, s) => acc + s.latency, 0) / shards.length;
      const stats = `Stores: ${customers.length}, AvgLatency: ${avgLatency.toFixed(0)}ms, ActiveNodes: ${shards.length}`;
      const result = await generateOpsDailySummary(stats);
      setHealth(result);
    };
    fetchHealth();
  }, [customers, shards]);

  const handleResolve = async () => {
    if (!resolverInput.trim() || isResolving) return;
    setIsResolving(true);
    const hotShard = shards.find(s => s.status === 'Hot') || shards[1];
    const mockLogs = `Node-${hotShard.id} Latency Spike: ${hotShard.latency}ms. CPU at ${hotShard.load}%. Regional Queue: 1200 msgs.`;
    const result = await getSystemOptimization(resolverInput, mockLogs);
    setResolutions(prev => [result, ...prev]);
    setResolverInput('');
    setIsResolving(false);
  };

  const handleApplyPatch = async (res: any) => {
    setIsDeploying(true);

    // Industrial deployment delay
    await new Promise(r => setTimeout(r, 2000));

    const patchId = `SOV-${Math.floor(Math.random()*10000)}`;
    const newPatch: AppliedPatch = {
      id: patchId,
      timestamp: new Date().toISOString(),
      diagnosis: res.diagnosis,
      diff: res.patch_code,
      impact: res.impact_analysis,
      status: 'DEPLOYED'
    };

    setAppliedPatches(prev => [newPatch, ...prev]);

    // FUNCTIONAL IMPACT: Optimize the high-load nodes
    setShards(prev => prev.map(s => {
      if (s.status === 'Hot' || s.status === 'Warning') {
        return { 
          ...s, 
          load: Math.max(15, s.load - 50), 
          latency: Math.max(40, s.latency - 300), 
          status: 'Healthy', 
          color: 'bg-emerald-500' 
        };
      }
      return s;
    }));

    setResolutions(prev => prev.filter(r => r.diagnosis !== res.diagnosis));
    setIsDeploying(false);
  };

  return (
    <div className="space-y-10 pb-20 animate-in fade-in duration-700 -m-10 p-10 min-h-screen bg-[#02040a] text-white font-mono relative selection:bg-indigo-500">
      {/* Deployment Progress Mask */}
      {isDeploying && (
        <div className="fixed inset-0 bg-black/95 z-[200] flex flex-col items-center justify-center space-y-10">
           <div className="w-24 h-24 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin shadow-[0_0_50px_rgba(16,185,129,0.3)]"></div>
           <div className="text-center space-y-3">
             <h3 className="text-4xl font-black italic tracking-tighter uppercase text-emerald-400">Deploying Infra Config</h3>
             <p className="text-[10px] text-slate-500 uppercase tracking-[0.5em] animate-pulse">Syncing state across regional matrix...</p>
           </div>
           <div className="w-full max-w-lg h-1.5 bg-slate-900 rounded-full overflow-hidden">
             <div className="h-full bg-emerald-500 animate-progress"></div>
           </div>
        </div>
      )}

      <header className="flex flex-col lg:flex-row lg:items-end justify-between gap-8 border-b border-white/10 pb-10 relative z-10">
        <div className="space-y-4">
          <div className="flex items-center gap-6">
             <div className="w-20 h-20 bg-slate-900 border border-white/20 rounded-[2rem] flex items-center justify-center text-5xl shadow-[0_0_40px_rgba(79,70,229,0.2)]">🛡️</div>
             <div>
               <div className="flex items-center gap-3 mb-2">
                 <span className="bg-rose-600 text-white text-[10px] px-3 py-1 rounded font-black tracking-widest uppercase italic">System Architect</span>
                 <span className="text-[10px] text-slate-500 uppercase font-black">Live Environment</span>
               </div>
               <h2 className="text-7xl font-black italic tracking-tighter text-white uppercase leading-none">Ops Command</h2>
             </div>
          </div>
        </div>
        <div className="flex gap-4">
           <button onClick={() => setView('superadmin')} className="px-10 py-5 bg-white text-black rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] shadow-2xl hover:scale-105 active:scale-95 transition-all">Regional Matrix ➔</button>
