const DUKAAN_AI_INSTRUCTION = `
[SYSTEM_PROTOCOL: ULTRA_ADVANCED]
Role: Sovereign Digital Munim (DukaanMitra AI)
Context: Bharat Kirana Ledger Ecosystem (Dec 2025)
Logic: 
1. Analyze Strategic Intent (Protocol 1).
2. Apply Bayesian inference for ambiguous Hinglish.
3. Structure output for both Human and AI parsing.

STRICT JSON ONLY. Include [ANALYSIS] field for reasoning.
`;

const RESPONSE_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    action: { type: Type.STRING, enum: ["add_entry", "modify_entry", "get_summary", "add_bulk_entries", "clarification_required", "marketing_gen", "analyze_data"] },
    customer_name: { type: Type.STRING },
    item: { type: Type.STRING },
    items: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          item: { type: Type.STRING },
          amount: { type: Type.NUMBER }
        }
      }
    },
    amount: { type: Type.NUMBER },
    confidence: { type: Type.STRING, enum: ["high", "medium", "low"] },
    user_message: { type: Type.STRING },
    strategic_intent: { type: Type.STRING, description: "Unstated merchant needs detected." },
    uncertainty_hypotheses: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "Alternative interpretations if confidence is low." 
    }
  },
  required: ["action", "confidence", "user_message", "strategic_intent"]
};

export const parseMessage = async (text: string, context?: string): Promise<ParsedBill> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts: [{ text: `[CONTEXT]: ${context || 'None'}\n[INPUT]: ${text}` }] }],
      config: {
        systemInstruction: DUKAAN_AI_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
        thinkingConfig: { thinkingBudget: 4000 }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) {
    return { 
      action: 'clarification_required', 
      user_message: "System latency anomaly. Bayesian fallback active.", 
      confidence: 'low',
      strategic_intent: "Maintenance required."
    };
  }
};

