import { GoogleGenAI, Type } from "@google/genai";
import { ParsedBill, Transaction, BlogPost, OpsHealthSnapshot } from "../types";

const DUKAAN_SOVEREIGN_INSTRUCTION = `
[SYSTEM_PROTOCOL: SOVEREIGN_INTELLIGENCE_v1M]
Role: Perfect Digital Munim.
Logic: 
1. TEMPORAL LEARNING: Use historical patterns to predict unstated needs.
2. NEGATIVE LEARNING: Ignore conversational noise without cost.
3. QUANTUM PARSING: Evaluate multiple semantic interpretations simultaneously.

STRICT JSON OUTPUT. Include [STRATEGIC_PREDICTION] for future merchant actions.
`;

export const parseMessage = async (text: string, context?: string): Promise<ParsedBill> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts: [{ text: `[STATE]: ${context || 'Initial'}\n[INGRESS]: ${text}` }] }],
      config: {
        systemInstruction: DUKAAN_SOVEREIGN_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            action: { type: Type.STRING, enum: ["add_entry", "modify_entry", "get_summary", "marketing_gen", "clarification_required"] },
            customer_name: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            items: { type: Type.STRING },
            confidence: { type: Type.NUMBER },
            user_message: { type: Type.STRING },
            strategic_intent: { type: Type.STRING },
            uncertainty_hypotheses: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["action", "confidence", "user_message", "strategic_intent"]
        },
        thinkingConfig: { thinkingBudget: 8000 }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) {
    return { 
      action: 'clarification_required', 
      user_message: "Quantum link unstable. Retrying via standard Bayesian path...", 
      confidence: 0.1,
      strategic_intent: "System auto-recovery triggered."
    };
  }
};

